"""
Keskon Regarde 🎬
Application cinématique de recommandation de films.
Design : fond bleu nuit profond, hero banner, affiches TMDB, onboarding profil.
Dépendances : streamlit, pandas, numpy, requests
"""

import streamlit as st
import streamlit.components.v1 as components
import html as html_mod
import pandas as pd
import numpy as np
import hashlib, json, gzip, base64, re, urllib.request, urllib.parse
import warnings
warnings.filterwarnings("ignore")

# ══════════════════════════════════════════════════════════════════════
# DONNÉES EMBARQUÉES
# ══════════════════════════════════════════════════════════════════════
MOVIES_B64 = ""
TMDB_KEY   = "8265bd1679663a7ea12ac168da84d2e8"
TMDB_IMG_W = "https://image.tmdb.org/t/p/w342"
TMDB_IMG_O = "https://image.tmdb.org/t/p/original"
TMDB_SRCH  = "https://api.themoviedb.org/3/search/movie"

@st.cache_data(show_spinner=False)
def load_movies():
    raw = gzip.decompress(base64.b64decode(MOVIES_B64)).decode()
    df  = pd.DataFrame(json.loads(raw))
    df["GenreList"] = df["Genres"].str.split("|")
    genres = sorted({g for gl in df["GenreList"] for g in gl})
    for g in genres:
        df[g] = df["GenreList"].apply(lambda gl: int(g in gl))
    return df, genres

@st.cache_data(show_spinner=False, ttl=86400)
def get_poster(title: str, year: int, size="w342") -> str:
    base = TMDB_IMG_W if size == "w342" else TMDB_IMG_O
    for attempt in [(title, year), (title, None)]:
        try:
            p = {"api_key": TMDB_KEY, "query": attempt[0], "language": "fr-FR"}
            if attempt[1]: p["year"] = attempt[1]
            url = f"{TMDB_SRCH}?{urllib.parse.urlencode(p)}"
            req = urllib.request.Request(url, headers={"User-Agent": "KeskonRegarde/2.0"})
            with urllib.request.urlopen(req, timeout=5) as r:
                data = json.loads(r.read())
            for res in data.get("results", []):
                if res.get("poster_path"):
                    return base + res["poster_path"]
        except Exception:
            pass
    return ""

