# ══════════════════════════════════════════════════════════════════════
# RECOMMENDATION ENGINE
# ══════════════════════════════════════════════════════════════════════
def cosine(v, M):
    nv = np.linalg.norm(v); nm = np.linalg.norm(M, axis=1)
    if nv < 1e-10: return np.zeros(M.shape[0])
    d = nm * nv; d[d < 1e-10] = 1e-10
    return M.dot(v) / d

def genre_vec(rd, movies, genres):
    if not rd: return np.zeros(len(genres))
    idx = movies.set_index("MovieID")[genres]
    w = np.zeros(len(genres)); t = 0.0
    for ms, note in rd.items():
        mid = int(ms)
        if mid not in idx.index: continue
        wt = float(note)/5.0; w += idx.loc[mid].values.astype(float)*wt; t += wt
    return w / max(t, 1e-10)

def get_reco(rd, movies, genres, n=18):
    rated = {int(k) for k in rd}
    uv = genre_vec(rd, movies, genres)
    c = movies[~movies["MovieID"].isin(rated)].copy()
    if c.empty: return c
    c["_score"] = cosine(uv, c[genres].values.astype(float))
    return c.nlargest(n, "_score").reset_index(drop=True)

def get_trending(movies, excl=set(), n=18):
    return movies[~movies["MovieID"].isin(excl)].sort_values("Year", ascending=False).head(n).reset_index(drop=True)

def get_by_genre(movies, genre, excl=set(), n=12):
    return movies[(movies[genre]==1)&(~movies["MovieID"].isin(excl))].sort_values("Year",ascending=False).head(n).reset_index(drop=True)

