def poster_html(title, year, genres, mode="card"):
    """Return img or fallback div HTML."""
    url = get_poster(title, year)
    bg, acc = gcol(genres)
    letter  = title[0].upper()
    cls     = "kr-card-poster" if mode == "card" else ""
    if url:
        return (
            f'<img src="{url}" class="{cls}" '
            f'style="width:100%;aspect-ratio:2/3;object-fit:cover;display:block;background:{bg};" '
            f'loading="lazy" '
            f'onerror="this.onerror=null;this.style.display=\'none\';">'
        )
    else:
        return (
            f'<div class="kr-card-poster-fb" '
            f'style="background:linear-gradient(160deg,{bg},#0C1120);">'
            f'<span style="font-size:2.8rem;font-weight:900;color:{acc}30;">{letter}</span>'
            f'</div>'
        )

