def render_row(df, label, badge="", show_score=False, kpfx="r", ncols=6):
    if df.empty: return
    ur = st.session_state.user_ratings
    genre1 = lambda g: g.split("|")[0]

    st.markdown(f"""
    <div class="kr-section">
        <div class="kr-section-head">
            <div class="kr-section-left">
                <span class="kr-section-title">{label}</span>
                {"<span class='kr-section-badge'>"+badge+"</span>" if badge else ""}
            </div>
        </div>
    </div>""", unsafe_allow_html=True)

    items = df.head(ncols * 2).reset_index(drop=True)
    n     = min(len(items), ncols)

    # Render all cards as a single HTML block to avoid Streamlit columns + unsafe_allow_html rendering bug
    card_width = f"calc({100//n}% - 10px)"
    cards_html = ""
    for i in range(n):
        if i >= len(items): break
        row   = items.iloc[i]
        mid   = row["MovieID"]
        rated = ur.get(str(mid))
        g1    = html_mod.escape(genre1(str(row["Genres"])))
        safe_title  = html_mod.escape(str(row["Title"]))
        safe_genres = html_mod.escape(" · ".join(str(row["Genres"]).split("|")[:2]))
        score_h = f'<div class="kr-card-score">{min(int(row["_score"]*100),99)}%</div>' if show_score and "_score" in row and row["_score"]>0 else ""
        rated_h = f'<div class="kr-card-rated">{"\u2605"*int(rated)}</div>' if rated else ""
        poster = poster_html(row["Title"], row["Year"], row["Genres"])
        cards_html += f"""<div class="kr-card" style="width:{card_width};display:inline-block;vertical-align:top;margin:0 5px;">
{poster}<div class="kr-card-genre-tag">{g1}</div>{score_h}{rated_h}
<div class="kr-card-body"><div class="kr-card-year">{int(row["Year"])}</div>
<div class="kr-card-title">{safe_title}</div>
<div class="kr-card-genres">{safe_genres}</div></div></div>"""

    st.markdown(
        f'<div style="padding:0 2.5rem;">' +
        f'<div style="display:flex;gap:10px;align-items:flex-start;">{cards_html}</div>' +
        f'</div>',
        unsafe_allow_html=True
    )

    # Buttons in columns for interactivity
    cols = st.columns(n, gap="small")
    for i in range(n):
        if i >= len(items): break
        row   = items.iloc[i]
        mid   = row["MovieID"]
        rated = ur.get(str(mid))
        with cols[i]:
            lbl = f'{"\u2605"*int(rated)} Modifier' if rated else "\u2606 Noter"
            if st.button(lbl, key=f"{kpfx}_{mid}_{i}"):
                st.session_state.sel_movie    = mid
                st.session_state.pending_star = int(rated) if rated else 0
                st.rerun()

    st.markdown("<div style='margin-bottom:1rem'></div>", unsafe_allow_html=True)
