def render_modal():
    mid = st.session_state.sel_movie
    if not mid: return
    mrow = movies_df[movies_df["MovieID"]==mid]
    if mrow.empty: return
    mrow     = mrow.iloc[0]
    existing = st.session_state.user_ratings.get(str(mid), 0)
    cur      = st.session_state.get("pending_star", int(existing))
    poster_url = get_poster(mrow["Title"], mrow["Year"])
    bg, acc  = gcol(mrow["Genres"])

    if poster_url:
        poster_part = f'<div class="kr-modal-poster"><img src="{poster_url}" alt="affiche"></div>'
    else:
        poster_part = f'<div class="kr-modal-poster-fb">🎬</div>'

    st.markdown(f"""
    <div class="kr-modal">
        <div class="kr-modal-inner">
            {poster_part}
            <div style="flex:1;">
                <div class="kr-modal-title">{mrow["Title"]}</div>
                <div class="kr-modal-meta">
                    {int(mrow["Year"])} &nbsp;·&nbsp;
                    {mrow["Genres"].replace("|"," · ")}
                </div>
                <div class="kr-modal-label">Donnez votre note</div>
                <div class="kr-rate-sub">Cliquez sur les étoiles ci-dessous</div>
                <div class="kr-star-hint">{STAR_LABELS.get(cur,"")}</div>
            </div>
        </div>
    </div>""", unsafe_allow_html=True)

    # Stars
    st.markdown('<div class="star-zone">', unsafe_allow_html=True)
    _, sc, _ = st.columns([1.5, 5, 1.5])
    with sc:
        scols = st.columns(5)
        for i, sc2 in enumerate(scols, 1):
            lit = i <= cur
            with sc2:
                if lit: st.markdown('<div class="star-lit">', unsafe_allow_html=True)
                if st.button("★" if lit else "☆", key=f"ms_{i}", use_container_width=True):
                    st.session_state.pending_star = i
                    st.rerun()
                if lit: st.markdown("</div>", unsafe_allow_html=True)
    st.markdown("</div>", unsafe_allow_html=True)

    # Action buttons
    st.markdown("<div style='height:0.6rem'></div>", unsafe_allow_html=True)
    _, b1, b2, b3, _ = st.columns([1.5, 2.2, 2.2, 2.2, 1.5])
    with b1:
        if st.button("✓  Valider", key="mok", disabled=(cur==0)):
            ur = st.session_state.user_ratings
            ur[str(mid)] = cur
            save_ratings(st.session_state.username, ur)
            st.session_state.just_rated   = mrow["Title"]
            st.session_state.sel_movie    = None
            st.session_state.pending_star = 0
            st.rerun()
    with b2:
        st.markdown('<div class="btn-ghost">', unsafe_allow_html=True)
        if st.button("✗  Annuler", key="mcancel"):
            st.session_state.sel_movie    = None
            st.session_state.pending_star = 0
            st.rerun()
        st.markdown("</div>", unsafe_allow_html=True)
    with b3:
        if existing:
            st.markdown('<div class="btn-danger">', unsafe_allow_html=True)
            if st.button("🗑  Retirer", key="mdel"):
                ur = st.session_state.user_ratings
                ur.pop(str(mid), None)
                save_ratings(st.session_state.username, ur)
                st.session_state.sel_movie    = None
                st.session_state.pending_star = 0
                st.rerun()
            st.markdown("</div>", unsafe_allow_html=True)

