            su_p2 = st.text_input("Confirmer le mot de passe", type="password", key="su_p2", placeholder="Répétez")
            st.markdown("<div style='height:0.8rem'></div>", unsafe_allow_html=True)
            if st.button("Créer mon compte  →", key="btn_signup"):
                db = get_db()
                err = None
                if len(su_u.strip()) < 3: err = "Pseudo trop court (min. 3 caractères)."
                elif su_u.strip() in db:   err = "Ce pseudo est déjà pris."
                elif len(su_p) < 4:        err = "Mot de passe trop court (min. 4 caractères)."
                elif su_p != su_p2:        err = "Les mots de passe ne correspondent pas."
                if err:
                    st.error(err)
                else:
                    db[su_u.strip()] = {"pw": hash_pw(su_p), "age": "", "csp": "", "genres": []}
                    save_db(db)
                    st.session_state.username     = su_u.strip()
                    st.session_state.user_ratings = {}
                    st.session_state.ob_age       = ""
                    st.session_state.ob_csp       = ""
                    st.session_state.ob_genres    = []
                    st.session_state.page         = "onboard"
                    st.session_state.onboard_step = 1
                    st.rerun()

